import{_ as a,c as t,o as n,a2 as r}from"./chunks/framework.aRVg8jgk.js";const m=JSON.parse('{"title":"Advanced Use Cases","description":"Real-world Lynq patterns: custom domains, blue-green deployments, multi-tier stacks, database-per-node, feature flags, and preview environments.","frontmatter":{"description":"Real-world Lynq patterns: custom domains, blue-green deployments, multi-tier stacks, database-per-node, feature flags, and preview environments."},"headers":[],"relativePath":"advanced-use-cases.md","filePath":"advanced-use-cases.md","lastUpdated":1779353865000}'),o={name:"advanced-use-cases.md"};function s(i,e,d,l,c,p){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="advanced-use-cases" tabindex="-1">Advanced Use Cases <a class="header-anchor" href="#advanced-use-cases" aria-label="Permalink to &quot;Advanced Use Cases&quot;">​</a></h1><p>Seven reference patterns. Each has a full guide with working YAML.</p><h2 id="which-pattern-do-i-need" tabindex="-1">Which Pattern Do I Need? <a class="header-anchor" href="#which-pattern-do-i-need" aria-label="Permalink to &quot;Which Pattern Do I Need?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>My requirement</th><th>Pattern</th></tr></thead><tbody><tr><td>Per-PR isolated environments, automatic cleanup</td><td><a href="#preview-environments">Preview Environments</a></td></tr><tr><td>Developer/test sandboxes per account</td><td><a href="#sandbox-environments">Sandbox Environments</a></td></tr><tr><td>Zero-downtime deploys, one-SQL-statement rollback</td><td><a href="#blue-green-deployments">Blue-Green Deployments</a></td></tr><tr><td>Customers bring their own domain + TLS</td><td><a href="#custom-domain-provisioning">Custom Domain Provisioning</a></td></tr><tr><td>Web, API, worker, data tiers independently scaled</td><td><a href="#multi-tier-application-stack">Multi-Tier Application Stack</a></td></tr><tr><td>Complete data isolation per node (compliance)</td><td><a href="#database-per-node">Database-per-Node</a></td></tr><tr><td>Enable/disable features per plan without redeployment</td><td><a href="#dynamic-feature-flags">Dynamic Feature Flags</a></td></tr></tbody></table><h2 id="preview-environments" tabindex="-1">Preview Environments <a class="header-anchor" href="#preview-environments" aria-label="Permalink to &quot;Preview Environments&quot;">​</a></h2><p><strong>Per-PR environments provisioned from CI with a single SQL INSERT. Deleting the row cleans up every resource.</strong></p><p>CI inserts one row per open PR — Lynq provisions a namespace, Deployment, Service, and TLS Ingress within ~60 seconds. When the PR closes, CI runs <code>DELETE</code>. No orphan environments, no stale namespaces.</p><p><strong><a href="./use-case-preview-environments.html">Full guide →</a></strong></p><h2 id="sandbox-environments" tabindex="-1">Sandbox Environments <a class="header-anchor" href="#sandbox-environments" aria-label="Permalink to &quot;Sandbox Environments&quot;">​</a></h2><p><strong>Isolated API sandbox environments per developer account — provisioned automatically, updated on plan change, torn down on account close.</strong></p><p>Each account row maps to one sandbox: isolated namespace, API server, mock webhook sink, and per-account config. Plan upgrades reconcile resource limits automatically.</p><p><strong><a href="./use-case-sandbox-environments.html">Full guide →</a></strong></p><h2 id="blue-green-deployments" tabindex="-1">Blue-Green Deployments <a class="header-anchor" href="#blue-green-deployments" aria-label="Permalink to &quot;Blue-Green Deployments&quot;">​</a></h2><p><strong>Zero-downtime deploys controlled by a single database column. Roll back with one SQL UPDATE.</strong></p><p>An <code>active_color</code> column determines which environment is live. Lynq keeps both running; the Service selector follows the column value.</p><p><strong><a href="./use-case-blue-green.html">Full guide →</a></strong></p><h2 id="custom-domain-provisioning" tabindex="-1">Custom Domain Provisioning <a class="header-anchor" href="#custom-domain-provisioning" aria-label="Permalink to &quot;Custom Domain Provisioning&quot;">​</a></h2><p><strong>Each node gets its own domain with automatic DNS and TLS — driven by a URL column in your database.</strong></p><p>A <code>custom_domain</code> column triggers ExternalDNS record creation and cert-manager certificate provisioning. The domain goes live without any manual configuration.</p><p><strong><a href="./use-case-custom-domains.html">Full guide →</a></strong></p><h2 id="multi-tier-application-stack" tabindex="-1">Multi-Tier Application Stack <a class="header-anchor" href="#multi-tier-application-stack" aria-label="Permalink to &quot;Multi-Tier Application Stack&quot;">​</a></h2><p><strong>Separate templates for web, API, worker, and data tiers — each independently scaled and lifecycled.</strong></p><p>Multiple LynqForms reference the same hub. Each tier gets its own LynqNode and can be updated, scaled, or replaced without touching the others.</p><p><strong><a href="./use-case-multi-tier.html">Full guide →</a></strong></p><h2 id="database-per-node" tabindex="-1">Database-per-Node <a class="header-anchor" href="#database-per-node" aria-label="Permalink to &quot;Database-per-Node&quot;">​</a></h2><p><strong>A dedicated cloud database per node, provisioned via Crossplane. Required for compliance isolation.</strong></p><p>Each node row triggers an RDS/Cloud SQL instance (or isolated schema/database on a shared instance). Credentials are written to Kubernetes Secrets automatically.</p><p><strong><a href="./use-case-database-per-tenant.html">Full guide →</a></strong></p><h2 id="dynamic-feature-flags" tabindex="-1">Dynamic Feature Flags <a class="header-anchor" href="#dynamic-feature-flags" aria-label="Permalink to &quot;Dynamic Feature Flags&quot;">​</a></h2><p><strong>Enable or disable features per node via database columns — no redeployment needed.</strong></p><p>A boolean column in your database maps to a Kubernetes resource. Set the column to <code>false</code>; Lynq removes the resource on the next sync. Works for infrastructure features (dedicated queues, extra replicas) and application flags (env vars).</p><p><strong><a href="./use-case-feature-flags.html">Full guide →</a></strong></p><h2 id="combining-patterns" tabindex="-1">Combining Patterns <a class="header-anchor" href="#combining-patterns" aria-label="Permalink to &quot;Combining Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Recommended combination</th></tr></thead><tbody><tr><td>SaaS platform</td><td>Multi-Tier + Custom Domains + Feature Flags + Blue-Green</td></tr><tr><td>Enterprise B2B</td><td>Database-per-Node + Multi-Tier + Blue-Green</td></tr><tr><td>Developer platform</td><td>Sandbox Environments + Feature Flags</td></tr><tr><td>Startup / early growth</td><td>Feature Flags + Custom Domains + Blue-Green</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./templates.html">Templates</a> — All template variables and functions.</li><li><a href="./policies.html">Policies</a> — DeletionPolicy for safe teardown, CreationPolicy for one-time resources.</li><li><a href="./dependencies.html">Dependencies</a> — Ordered provisioning for multi-resource patterns.</li><li><a href="./multi-tenant-isolation.html">Multi-Tenant Isolation</a> — Namespace-per-node and NetworkPolicy.</li></ul>',36)])])}const h=a(o,[["render",s]]);export{m as __pageData,h as default};
